import vex

# Initialize Vex client
vex_client = vex.Client(api_key="your-vex-api-key")

# Define verification criteria for content generation
content_checks = {
    "brand_consistency": {
        "type": "semantic_similarity",
        "reference": "Our brand voice: professional, innovative, customer-focused",
        "threshold": 0.85
    },
    "factual_accuracy": {
        "type": "fact_check",
        "sources": result['citations']
    },
    "seo_compliance": {
        "type": "keyword_density",
        "target_keywords": ["AI", "content", "generation"],
        "min_density": 0.02
    },
    "tone_adherence": {
        "type": "sentiment_analysis",
        "target_sentiment": "professional"
    }
}

# Verify final graph output
try:
    verified_result = vex_client.verify(
        input=result['merged_content'],
        checks=content_checks,
        context={
            "topic": result['topic'],
            "brand_guidelines": result['brand_voice']
        }
    )

    if verified_result['passed']:
        print("✅ Content ready for publishing")
    else:
        print("❌ Verification failed:", verified_result['failures'])

except vex.VerificationError as e:
    print("Verification blocked execution:", e.errors)

async def vex_merge_validator(state: ContentState) -> ContentState:
    """Validate merged state consistency before editor node"""

    merge_checks = {
        "tone_compatibility": {
            "type": "semantic_similarity",
            "texts": [state['draft'], state['brand_voice']],
            "threshold": 0.75,
            "description": "Draft must align with brand voice"
        },
        "content_completeness": {
            "type": "llm_rubric",
            "rubric": "Is this content complete with research, structure, and citations?",
            "threshold": "PASS"
        },
        "no_conflicts": {
            "type": "conflict_detection",
            "fields": ['facts', 'brand_voice'],
            "max_conflicts": 0
        }
    }

    validation = vex_client.verify(
        input=state,
        checks=merge_checks,
        context={'stage': 'pre-editor-merge'}
    )

    if not validation['passed']:
        raise ValueError(f"Merge validation failed: {validation['failures']}")

    state['merge_validated'] = True
    state['validation_scores'] = validation['scores']

    return state

# Replace simple merge with validated merge
workflow.add_node('validated_merge', vex_merge_validator)
workflow.add_edge('writer', 'validated_merge')  # From parallel branches
workflow.add_edge('brand_voice', 'validated_merge')
workflow.add_edge('validated_merge', 'editor')
